// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	log logrus.FieldLogger,
	cnpResource resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:               log,
		namespacePolicies: make(map[string]int),
		maxPerNamespace:   maxPerNamespace,
		cnpResource:       cnpResource,
	}
}

// Run starts the controller's event loop.
func (pqc *PolicyQuotaController) Run(ctx context.Context) error {
	pqc.log.Info("Starting PolicyQuotaController")
	defer pqc.log.Info("Stopped PolicyQuotaController")

	cnpEvents := pqc.cnpResource.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case event, ok := <-cnpEvents:
			if !ok {
				return nil
			}

			if event.Kind == resource.Sync {
				pqc.log.Debug("PolicyQuotaController synced")
				event.Done(nil)
				continue
			}

			var err error
			switch event.Kind {
			case resource.Upsert:
				err = pqc.onPolicyUpsert(event.Object)
			case resource.Delete:
				err = pqc.onPolicyDelete(event.Object)
			}
			event.Done(err)
		}
	}
}

// onPolicyUpsert handles the addition or update of a CiliumNetworkPolicy.
func (pqc *PolicyQuotaController) onPolicyUpsert(cnp *cilium_v2.CiliumNetworkPolicy) error {
	pqc.mu.Lock()
	defer pqc.mu.Unlock()

	ns := cnp.Namespace
	pqc.namespacePolicies[ns]++

	pqc.log.WithFields(logrus.Fields{
		logfields.PolicyName:      cnp.Name,
		logfields.K8sNamespace:    ns,
		"policyCount":             pqc.namespacePolicies[ns],
		"maxPerNamespace":         pqc.maxPerNamespace,
	}).Debug("CiliumNetworkPolicy upserted")

	return nil
}

// onPolicyDelete handles the deletion of a CiliumNetworkPolicy.
func (pqc *PolicyQuotaController) onPolicyDelete(cnp *cilium_v2.CiliumNetworkPolicy) error {
	pqc.mu.Lock()
	defer pqc.mu.Unlock()

	ns := cnp.Namespace
	if count, exists := pqc.namespacePolicies[ns]; exists && count > 0 {
		pqc.namespacePolicies[ns]--
		if pqc.namespacePolicies[ns] == 0 {
			delete(pqc.namespacePolicies, ns)
		}
	}

	pqc.log.WithFields(logrus.Fields{
		logfields.PolicyName:      cnp.Name,
		logfields.K8sNamespace:    ns,
		"policyCount":             pqc.namespacePolicies[ns],
		"maxPerNamespace":         pqc.maxPerNamespace,
	}).Debug("CiliumNetworkPolicy deleted")

	return nil
}

// CheckQuota returns an error if the namespace has exceeded its policy quota.
func (pqc *PolicyQuotaController) CheckQuota(namespace string) error {
	pqc.mu.Lock()
	defer pqc.mu.Unlock()

	count := pqc.namespacePolicies[namespace]
	if count >= pqc.maxPerNamespace {
		return fmt.Errorf("policy quota exceeded for namespace %q: current=%d, max=%d",
			namespace, count, pqc.maxPerNamespace)
	}

	return nil
}

// GetNamespacePolicyCounts returns a copy of the current policy counts per namespace.
// This method is primarily for testing purposes.
func (pqc *PolicyQuotaController) GetNamespacePolicyCounts() map[string]int {
	pqc.mu.Lock()
	defer pqc.mu.Unlock()

	counts := make(map[string]int, len(pqc.namespacePolicies))
	for ns, count := range pqc.namespacePolicies {
		counts[ns] = count
	}
	return counts
}
