)

type mockResourceEvents struct {
	mu     sync.Mutex
	events []resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func (m *mockResourceEvents) send(event resource.Event[*cilium_v2.CiliumNetworkPolicy]) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.events = append(m.events, event)
}

func TestCheckQuota(t *testing.T) {
	log := logrus.New().WithField("test", "true")
	mockCNPResource := &mockCNPResource{}

	pqc := NewPolicyQuotaController(log, mockCNPResource, 5)

	// Manually populate the namespace policies
	pqc.mu.Lock()
	pqc.namespacePolicies["default"] = 4
	pqc.namespacePolicies["kube-system"] = 1
	pqc.mu.Unlock()

	// Test: namespace with room under quota
	err := pqc.CheckQuota("default")
	assert.NoError(t, err, "expected no error when below quota")

	// Test: namespace that hasn't been seen yet
	err = pqc.CheckQuota("new-namespace")
	assert.NoError(t, err, "expected no error for namespace at 0 policies")

	// Manually set to max
	pqc.mu.Lock()
	pqc.namespacePolicies["test"] = 5
	pqc.mu.Unlock()

	// Test: namespace at quota limit
	err = pqc.CheckQuota("test")
	assert.Error(t, err, "expected error when at quota limit")
	assert.Contains(t, err.Error(), "policy quota exceeded")
}

func TestPolicyUpsertAndDelete(t *testing.T) {
	log := logrus.New().WithField("test", "true")
	mockCNPResource := &mockCNPResource{}

	pqc := NewPolicyQuotaController(log, mockCNPResource, 3)

	// Create a test policy
	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
	}

	// Test: upsert policy
	err := pqc.onPolicyUpsert(cnp)
	assert.NoError(t, err)

	counts := pqc.GetNamespacePolicyCounts()
	assert.Equal(t, 1, counts["default"], "expected 1 policy in default namespace")

	// Test: upsert another policy
	cnp2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-2",
			Namespace: "default",
		},
	}
	err = pqc.onPolicyUpsert(cnp2)
	assert.NoError(t, err)

	counts = pqc.GetNamespacePolicyCounts()
	assert.Equal(t, 2, counts["default"], "expected 2 policies in default namespace")

	// Test: delete policy
	err = pqc.onPolicyDelete(cnp)
	assert.NoError(t, err)

	counts = pqc.GetNamespacePolicyCounts()
	assert.Equal(t, 1, counts["default"], "expected 1 policy after deletion")

	// Test: delete the last policy
	err = pqc.onPolicyDelete(cnp2)
	assert.NoError(t, err)

	counts = pqc.GetNamespacePolicyCounts()
	_, exists := counts["default"]
	assert.False(t, exists, "expected default namespace to be removed from map after all policies deleted")
}

func TestMultipleNamespaces(t *testing.T) {
	log := logrus.New().WithField("test", "true")
	mockCNPResource := &mockCNPResource{}

	pqc := NewPolicyQuotaController(log, mockCNPResource, 3)

	// Create policies in different namespaces
	namespaces := []string{"default", "kube-system", "custom"}

	for _, ns := range namespaces {
		for i := 0; i < 2; i++ {
			cnp := &cilium_v2.CiliumNetworkPolicy{
				ObjectMeta: metav1.ObjectMeta{
					Name:      "policy-" + ns + "-" + string(rune(i)),
					Namespace: ns,
				},
			}
			err := pqc.onPolicyUpsert(cnp)
			assert.NoError(t, err)
		}
	}

	counts := pqc.GetNamespacePolicyCounts()
	for _, ns := range namespaces {
		assert.Equal(t, 2, counts[ns], "expected 2 policies in %s namespace", ns)
	}

	// Test quota check for each namespace
	for _, ns := range namespaces {
		err := pqc.CheckQuota(ns)
		assert.NoError(t, err, "expected no error for %s at 2/3 quota", ns)
	}
}

func TestQuotaExceededError(t *testing.T) {
	log := logrus.New().WithField("test", "true")
	mockCNPResource := &mockCNPResource{}

	pqc := NewPolicyQuotaController(log, mockCNPResource, 2)

	// Add policies to max
	for i := 0; i < 2; i++ {
		cnp := &cilium_v2.CiliumNetworkPolicy{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "policy-" + string(rune(48+i)),
				Namespace: "limited",
			},
		}
		err := pqc.onPolicyUpsert(cnp)
		assert.NoError(t, err)
	}

	// Test: at quota
	err := pqc.CheckQuota("limited")
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "policy quota exceeded")
	assert.Contains(t, err.Error(), "limited")
	assert.Contains(t, err.Error(), "current=2")
	assert.Contains(t, err.Error(), "max=2")
}

func TestRunMethod(t *testing.T) {
	log := logrus.New().WithField("test", "true")
	mockCNPResource := &mockCNPResourceWithChannel{}

	pqc := NewPolicyQuotaController(log, mockCNPResource, 3)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Create test policies
	cnp1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-1",
			Namespace: "default",
		},
	}

	cnp2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-2",
			Namespace: "default",
		},
	}

	// Send events to the mock resource
	done1 := make(chan error, 1)
	done2 := make(chan error, 1)
	doneSync := make(chan error, 1)

	go func() {
		// Send events with a small delay
		mockCNPResource.eventChan <- resource.Event[*cilium_v2.CiliumNetworkPolicy]{
			Kind:   resource.Upsert,
			Object: cnp1,
			Key:    resource.Key{Name: cnp1.Name, Namespace: cnp1.Namespace},
			Done: func(err error) {
				done1 <- err
			},
		}

		mockCNPResource.eventChan <- resource.Event[*cilium_v2.CiliumNetworkPolicy]{
			Kind:   resource.Upsert,
			Object: cnp2,
			Key:    resource.Key{Name: cnp2.Name, Namespace: cnp2.Namespace},
			Done: func(err error) {
				done2 <- err
			},
		}

		mockCNPResource.eventChan <- resource.Event[*cilium_v2.CiliumNetworkPolicy]{
			Kind: resource.Sync,
			Done: func(err error) {
				doneSync <- err
			},
		}

		// Give time for processing then cancel context
		close(mockCNPResource.eventChan)
	}()

	// Run the controller
	err := pqc.Run(ctx)
	require.NoError(t, err)

	// Verify done callbacks were called
	<-done1
	<-done2
	<-doneSync

	counts := pqc.GetNamespacePolicyCounts()
	assert.Equal(t, 2, counts["default"], "expected 2 policies in default namespace after Run")
}

